#include <iostream>
#include <string>
#include <vector>
#include <sstream>

// Engine class definition
class Engine {
private:
    std::string type;
    int horsepower;

public:
    Engine(std::string engineType, int hp) {
        this->type = engineType;
        this->horsepower = hp;
    }

    std::string getType() {
        return type;
    }

    int getHorsepower() {
        return horsepower;
    }

    std::string getInfo() {
        std::stringstream ss;
        ss << "Engine Type: " << type << ", Horsepower: " << horsepower;
        return ss.str();
    }
};

// Car class definition
class Car {
private:
    std::string make;
    Engine engine;

public:
    Car(std::string carMake, std::string engineType, int engineHp)
        : make(carMake), engine(engineType, engineHp) {
    }

    void displayCarInfo() {
        std::cout << "Car Make: " << make << std::endl;
        std::cout << "  " << engine.getInfo() << std::endl;
    }
};

int main() {
    Car car1("Toyota", "V6", 280);
    car1.displayCarInfo();

    Car car2("Ford", "V8", -350);
    car2.displayCarInfo();

    Car car3("Honda", "", 150);
    car3.displayCarInfo();

    return 0;
}
